/*! Minimal Toastify fallback (local) - if CDN is blocked.
 *  This is NOT the full Toastify library.
 *  It supports the subset used in this project: Toastify({ text, duration, close, gravity, position, style }).showToast()
 */
(function (global) {
  if (typeof global.Toastify === 'function') return;

  function ensureContainer(gravity) {
    var id = 'toastify-container-' + gravity;
    var el = document.getElementById(id);
    if (el) return el;

    el = document.createElement('div');
    el.id = id;
    el.style.position = 'fixed';
    el.style.zIndex = '999999';
    el.style.left = '0';
    el.style.right = '0';
    el.style.pointerEvents = 'none';
    el.style[gravity === 'bottom' ? 'bottom' : 'top'] = '16px';
    document.body.appendChild(el);
    return el;
  }

  global.Toastify = function (opts) {
    opts = opts || {};
    var api = {
      showToast: function () {
        try {
          var gravity = (opts.gravity === 'bottom') ? 'bottom' : 'top';
          var position = (opts.position === 'left') ? 'left' : (opts.position === 'center' ? 'center' : 'right');
          var container = ensureContainer(gravity);

          var toast = document.createElement('div');
          toast.className = 'toastify';
          toast.textContent = String(opts.text || '');
          toast.style.maxWidth = '480px';
          toast.style.margin = '8px auto';
          toast.style.padding = '10px 12px';
          toast.style.borderRadius = '6px';
          toast.style.background = '#323232';
          toast.style.color = '#fff';
          toast.style.fontSize = '14px';
          toast.style.boxShadow = '0 4px 12px rgba(0,0,0,.2)';
          toast.style.pointerEvents = 'auto';

          if (opts.style && typeof opts.style === 'object') {
            for (var k in opts.style) {
              if (Object.prototype.hasOwnProperty.call(opts.style, k)) {
                toast.style[k] = opts.style[k];
              }
            }
          }

          if (position === 'left') {
            toast.style.marginLeft = '16px';
            toast.style.marginRight = 'auto';
          } else if (position === 'right') {
            toast.style.marginLeft = 'auto';
            toast.style.marginRight = '16px';
          } else {
            toast.style.marginLeft = 'auto';
            toast.style.marginRight = 'auto';
          }

          if (opts.close) {
            var btn = document.createElement('button');
            btn.type = 'button';
            btn.textContent = '×';
            btn.style.border = '0';
            btn.style.background = 'transparent';
            btn.style.color = 'inherit';
            btn.style.fontSize = '18px';
            btn.style.marginLeft = '10px';
            btn.style.cursor = 'pointer';
            btn.onclick = function () {
              if (toast && toast.parentNode) toast.parentNode.removeChild(toast);
            };
            toast.appendChild(btn);
          }

          container.appendChild(toast);

          var duration = typeof opts.duration === 'number' ? opts.duration : 3000;
          if (duration > 0) {
            setTimeout(function () {
              if (toast && toast.parentNode) toast.parentNode.removeChild(toast);
            }, duration);
          }
        } catch (e) {
          // last resort
          try { console.log('[Toastify fallback]', opts.text); } catch (_) {}
        }
      }
    };
    return api;
  };

  global.Toastify.defaults = global.Toastify.defaults || {};
})(window);
